#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
timeline-source.md 再生成ツール（地域カラム付与）

使い方:
  python3 scripts/regen_timeline.py --dry   # ドライラン（統計・サンプルのみ）
  python3 scripts/regen_timeline.py         # 実書き換え

役割:
- 「地域」カラム（具体地名・国の単一トークン）を付与する。列順は
  いつ→どこ→なに になるよう  章|重要|掲載|年代|地域|事項
- 掲載（✓/—）は現状を保全する（＝この列はここでは触らない）。
  ※掲載の精査は「本編を読んで判断」する別工程で行う。語句一致では
    西ローマ/東ローマ/イエス等の中核トピックを取りこぼすため。
- 参考として、regex 推定の掲載との差分件数だけレポートに出す。
"""
import re, sys, glob, os

ROOT = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
SRC = os.path.join(ROOT, "timeline-source.md")

def load_corpus():
    text = ""
    for f in sorted(glob.glob(os.path.join(ROOT, "chapters", "*.md"))) + \
             sorted(glob.glob(os.path.join(ROOT, "gaiden", "*.md"))):
        with open(f, encoding="utf-8") as fh:
            text += fh.read() + "\n"
    for ch in ("*","　"," ","「","」","『","』","（","）","(",")","、","。","・"):
        text = text.replace(ch, "")
    return text
CORPUS = load_corpus()

