def region_for(text):
    for region, kws in REGION_RULES:
        for kw in kws:
            if kw in text:
                return region
    return "？"

# --- 参考用 regex 掲載推定（保全方針のため出力には使わない） ---
STOP_KATA = set("ローマ ギリシア ギリシャ エジプト インド ペルシア ペルシャ アジア ヨーロッパ アフリカ アメリカ イギリス フランス ドイツ イタリア スペイン ポルトガル オランダ オリエント アラビア バルカン イベリア シベリア ロシア トルコ イラン ベトナム カンボジア インドネシア ビルマ メキシコ ブラジル ポーランド ハンガリー オーストリア スウェーデン シリア パレスチナ アイルランド スコットランド イングランド モンゴル チベット".split())
STOP_KANJI = set("戦争 条約 成立 即位 退位 建国 滅亡 制定 会議 同盟 改革 革命 統一 征服 侵入 遠征 反乱 占領 併合 建設 完成 発明 発見 出現 開始 終結 崩御 開催 締結 勃発 独立 王朝 帝国 王国 共和国 大統領 首相 皇帝 国王 民族 政府 時代 世紀 文化 制度 思想 宗教 都市 国家 領土 戦い 内乱 内戦 講和 進出 支配 統治 大戦 連邦 公国 王位 議会 憲法".split())
KATA = re.compile(r'[ァ-ヶー]{3,}'); KANJI = re.compile(r'[一-龠々]{2,}')
def published_regex(text):
    for m in list(KATA.findall(text)) + list(KANJI.findall(text)):
        if m in STOP_KATA or m in STOP_KANJI: continue
        if m in CORPUS: return True
    return False

# ---------------------------------------------------------------------------
HEADER_OLD = "| 章 | 重要 | 掲載 | 年代 | 事項 |"
HEADER_NEW = "| 章 | 重要 | 掲載 | 年代 | 地域 | 事項 |"
SEP_OLD = "|---|---|---|---|---|"
SEP_NEW = "|---|---|---|---|---|---|"

def process(dry=False):
    with open(SRC, encoding="utf-8") as f:
        lines = f.readlines()
    out = []
    n=0; unknown=0; reg_count={}
    unknown_rows=[]; samples=[]; flip_on=0; flip_off=0
    for ln in lines:
        s = ln.rstrip("\n")
        if s in (HEADER_OLD, HEADER_NEW): out.append(HEADER_NEW+"\n"); continue
        if s in (SEP_OLD, SEP_NEW):       out.append(SEP_NEW+"\n"); continue
        if s.startswith("| ") and not s.startswith("| 章 "):
            cells=[c.strip() for c in s.split("|")[1:-1]]
            if len(cells)==5:               # 旧5列: 章|重要|掲載|年代|事項
                ch,imp,pub,era,topic = cells
            elif len(cells)==6:             # 新6列: 地域を再計算（冪等）
                ch,imp,pub,era,_old,topic = cells
            else:
                out.append(ln); continue
            region = region_for(topic)
            n+=1; reg_count[region]=reg_count.get(region,0)+1
            pr = published_regex(topic)
            if pub=="—" and pr: flip_on+=1
            if pub=="✓" and not pr: flip_off+=1
            if region=="？":
                unknown+=1
                if len(unknown_rows)<80: unknown_rows.append(f"  {era} | {topic}")
            elif len(samples)<20:
                samples.append(f"  {region:9s}| {era} | {topic}")
            out.append(f"| {ch} | {imp} | {pub} | {era} | {region} | {topic} |\n")
        else:
            out.append(ln)
    print("="*60)
    print(f"データ行: {n}   地域未解決(？): {unknown}")
    print(f"（参考）掲載 現状 vs regex推定の差: —→✓ {flip_on} / ✓→— {flip_off} … 大きいほどregex不適合")
    print("地域分布:")
    for r,c in sorted(reg_count.items(), key=lambda x:-x[1]):
        print(f"   {r:10s} {c}")
    print("\n[地域サンプル]"); print("\n".join(samples))
    print(f"\n[地域 未解決 {unknown}件のうち先頭]"); print("\n".join(unknown_rows))
    if not dry:
        with open(SRC,"w",encoding="utf-8") as f: f.writelines(out)
        print("\n*** timeline-source.md を書き換えました ***")
    else:
        print("\n(dry-run)")

if __name__=="__main__":
    process(dry="--dry" in sys.argv)
